void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = GetPixel(vUv).x*(1-GetBlur2(vUv).x);
ret-=roam_sin.wzy*roam_cos.zxy;
ret += (1-GetPixel(vUv).x)*GetBlur1(vUv).x*vec3(2,1.2,0);

  fragColor = ret;
